  ctx.beginPath();
  ctx.moveTo(0, -r * 1.05);
  ctx.quadraticCurveTo(2, -r * 1.35, 1, -r * 1.55);
  ctx.strokeStyle = "#5d4037";
  ctx.lineWidth = 2;
