  ctx.fillStyle = "#5d4037";
  ctx.fillRect(-1.5, -r - 4, 3, 6);
  // 小叶
  ctx.beginPath();
  ctx.ellipse(4, -r - 2, 6, 3, 0.5, 0, Math.PI * 2);
