function drawFruit(ctx: CanvasRenderingContext2D, f: Fruit) {
  ctx.save();
  ctx.globalAlpha = f.opacity;
  ctx.translate(f.x, f.y);
  ctx.rotate(f.rot);

  if (f.type === "bomb") {
    drawBomb(ctx, f.r);
  } else {
    switch (f.shape) {
      case "watermelon":
        drawWatermelon(ctx, f.r);
        break;
      case "orange":
        drawOrange(ctx, f.r);
        break;
      case "apple":
        drawApple(ctx, f.r);
        break;
      case "grape":
        drawGrape(ctx, f.r);
        break;
      case "lemon":
        drawLemon(ctx, f.r);
        break;
    }
  }

  ctx.restore();
}

