  ctx.strokeStyle = "#1a4d1a";
  ctx.lineWidth = 2;
  for (let i = -3; i <= 3; i++) {
    ctx.beginPath();
    ctx.moveTo(i * r * 0.35, -r);
    ctx.quadraticCurveTo(i * r * 0.3, 0, i * r * 0.35, r);
    ctx.stroke();
  }
  ctx.restore();
  // 高光弧面
  ctx.beginPath();
  ctx.ellipse(-r * 0.3, -r * 0.3, r * 0.45, r * 0.25, -0.4, 0, Math.PI * 2);
