/* ---------- 常量 ---------- */
const GRAVITY = 0.22;
const BOMB_CHANCE = 0.15;
const CANVAS_H = window.innerWidth < 600 ? 300 : 360;
const STORAGE_KEY = "game_best_fruitslice";
