/* ---------- 接口 ---------- */
interface Fruit {
  id: number;
  x: number;
  y: number;
  r: number;
  vx: number;
  vy: number;
  color: string;
  innerColor: string;
  leafColor: string;
  type: "fruit" | "bomb";
  shape: "watermelon" | "orange" | "apple" | "grape" | "lemon" | "bomb";
  sliced: boolean;
  opacity: number;
  rot: number;
  rotV: number;
}

interface SliceHalf {
  x: number;
  y: number;
  r: number;
  vx: number;
  vy: number;
  color: string;
  innerColor: string;
  leafColor: string;
  shape: "watermelon" | "orange" | "apple" | "grape" | "lemon" | "bomb";
  rot: number;
  rotV: number;
  life: number;
}

interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  r: number;
  color: string;
  life: number;
  maxLife: number;
}

interface TrailPoint {
  x: number;
  y: number;
  life: number;
}

