import { AnimatePresence, motion } from "framer-motion";

/* ============================================================
   切水果 · Fruit Slice
   一刀两断，万念皆空
   ============================================================ */

/* ---------- 接口 ---------- */
interface Fruit {
  id: number;
  x: number;
  y: number;
  r: number;
  vx: number;
  vy: number;
  color: string;
  innerColor: string;
  leafColor: string;
  type: "fruit" | "bomb";
  shape: "watermelon" | "orange" | "apple" | "grape" | "lemon" | "bomb";
  sliced: boolean;
  opacity: number;
  rot: number;
  rotV: number;
}

interface SliceHalf {
  x: number;
  y: number;
  r: number;
  vx: number;
  vy: number;
  color: string;
  innerColor: string;
  leafColor: string;
  shape: "watermelon" | "orange" | "apple" | "grape" | "lemon" | "bomb";
  rot: number;
  rotV: number;
  life: number;
}

interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  r: number;
  color: string;
  life: number;
  maxLife: number;
}

interface TrailPoint {
  x: number;
  y: number;
  life: number;
}

/* ---------- 常量 ---------- */
const GRAVITY = 0.22;
const BOMB_CHANCE = 0.15;
const CANVAS_H = window.innerWidth < 600 ? 300 : 360;
const STORAGE_KEY = "game_best_fruitslice";
const ACHIEVEMENTS = [
  { score: 10, title: "初入刀道" },
  { score: 30, title: "刀锋渐利" },
  { score: 50, title: "刀光剑影" },
  { score: 100, title: "你已超脱凡尘" },
];

const SHAPES: Array<Exclude<Fruit["shape"], "bomb">> = ["watermelon", "orange", "apple", "grape", "lemon"];

/* ---------- 水果配置 ---------- */
function fruitConfig(shape: Exclude<Fruit["shape"], "bomb">): Pick<Fruit, "color" | "innerColor" | "leafColor" | "r"> {
  switch (shape) {
    case "watermelon":
      return { color: "#2d6a2d", innerColor: "#e74c3c", leafColor: "#1a4d1a", r: 32 };
    case "orange":
      return { color: "#e67e22", innerColor: "#f39c12", leafColor: "#27ae60", r: 24 };
    case "apple":
      return { color: "#c0392b", innerColor: "#fdebd0", leafColor: "#27ae60", r: 24 };
    case "grape":
      return { color: "#8e44ad", innerColor: "#d2b4de", leafColor: "#27ae60", r: 22 };
    case "lemon":
      return { color: "#f1c40f", innerColor: "#fef9e7", leafColor: "#27ae60", r: 22 };
  }
}

/* ---------- 音效 ---------- */
const playSliceSound = () => {
  try {
    const ctx = new AudioContext();
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = "sine";
    osc.frequency.setValueAtTime(1200, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(300, ctx.currentTime + 0.15);
    gain.gain.setValueAtTime(0.18, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.15);
    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.start(ctx.currentTime);
    osc.stop(ctx.currentTime + 0.15);
  } catch {
    /* 静音处理 */
  }
};

const playBombSound = () => {
  try {
    const ctx = new AudioContext();
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = "sawtooth";
    osc.frequency.setValueAtTime(150, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(40, ctx.currentTime + 0.25);
    gain.gain.setValueAtTime(0.25, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.25);
    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.start(ctx.currentTime);
    osc.stop(ctx.currentTime + 0.25);
  } catch {
    /* 静音处理 */
  }
};

/* ---------- 绘制水果（完整） ---------- */
function drawFruit(ctx: CanvasRenderingContext2D, f: Fruit) {
  ctx.save();
  ctx.globalAlpha = f.opacity;
  ctx.translate(f.x, f.y);
  ctx.rotate(f.rot);

  if (f.type === "bomb") {
    drawBomb(ctx, f.r);
  } else {
    switch (f.shape) {
      case "watermelon":
        drawWatermelon(ctx, f.r);
        break;
      case "orange":
        drawOrange(ctx, f.r);
        break;
      case "apple":
        drawApple(ctx, f.r);
        break;
      case "grape":
        drawGrape(ctx, f.r);
        break;
      case "lemon":
        drawLemon(ctx, f.r);
        break;
    }
  }

  ctx.restore();
}

