  const missedRef = useRef(0);
  const animFrameRef = useRef(0);

  // 同步 ref
  bestRef.current = bestScore;
  gameStateRef.current = gameState;

  /* ---------- 核心循环 ---------- */
  const gameLoop = useCallback(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    const w = canvas.width;
    const h = canvas.height;

    // 背景渐变
    const grad = ctx.createLinearGradient(0, 0, 0, h);
    grad.addColorStop(0, "#faf8f5");
    grad.addColorStop(1, "#f3f0ed");
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, w, h);

    if (gameStateRef.current !== "playing") {
      rafRef.current = requestAnimationFrame(gameLoop);
      return;
    }

    // 生成水果
    spawnTimerRef.current++;
    if (spawnTimerRef.current > 45 + Math.random() * 20) {
      spawnTimerRef.current = 0;
      fruitsRef.current.push(spawnFruit(w, h));
    }

    // 更新水果
    const fruits = fruitsRef.current;
    for (let i = fruits.length - 1; i >= 0; i--) {
      const f = fruits[i];
      f.vy += GRAVITY;
      f.x += f.vx;
      f.y += f.vy;
      f.rot += f.rotV;
      // 出界移除
      if (f.y > h + 60 && f.vy > 0) {
        if (f.type === "fruit" && !f.sliced) {
          missedRef.current++;
        }
        fruits.splice(i, 1);
        continue;
      }
      if (f.sliced) {
        f.opacity -= 0.05;
        if (f.opacity <= 0) {
          fruits.splice(i, 1);
        }
      }
    }

    // 更新切面半片
    const halves = halvesRef.current;
    for (let i = halves.length - 1; i >= 0; i--) {
      const hh = halves[i];
      hh.vy += GRAVITY * 0.6;
      hh.x += hh.vx;
      hh.y += hh.vy;
      hh.rot += hh.rotV;
      hh.life--;
      if (hh.life <= 0 || hh.y > h + 80) {
        halves.splice(i, 1);
      }
    }

    // 更新粒子
    const parts = particlesRef.current;
    for (let i = parts.length - 1; i >= 0; i--) {
      const p = parts[i];
      p.vy += 0.12;
      p.x += p.vx;
      p.y += p.vy;
      p.life--;
      if (p.life <= 0) {
        parts.splice(i, 1);
      }
    }

    // 更新轨迹
    const trail = trailRef.current;
    for (let i = trail.length - 1; i >= 0; i--) {
      trail[i].life--;
      if (trail[i].life <= 0) {
        trail.splice(i, 1);
      }
    }

    // 检查游戏结束（漏掉10个水果）
    if (missedRef.current >= 10) {
      gameStateRef.current = "over";
      setGameState("over");
      if (scoreRef.current > bestRef.current) {
        const newBest = scoreRef.current;
        setBestScore(newBest);
        try {
          localStorage.setItem(STORAGE_KEY, String(newBest));
        } catch {
          /* ignore */
        }
      }
    }

    // ---- 绘制 ----

    // 绘制轨迹
    for (const t of trail) {
      const alpha = t.life / 12;
      ctx.beginPath();
      ctx.arc(t.x, t.y, 3 * alpha, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(255,255,255,${alpha * 0.8})`;
      ctx.fill();
    }

    // 绘制水果
    for (const f of fruits) {
      if (!f.sliced) {
        drawFruit(ctx, f);
      }
    }

    // 绘制切面半片
    for (const hh of halves) {
      drawSliceHalf(ctx, hh);
    }

    // 绘制粒子
    for (const p of parts) {
      const alpha = p.life / p.maxLife;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.r * alpha, 0, Math.PI * 2);
      ctx.fillStyle = p.color.replace("1)", `${alpha})`);
      ctx.fill();
    }

    rafRef.current = requestAnimationFrame(gameLoop);
  }, []);

